{
  "name": "GradeMaster",
  "description": "A comprehensive grade management system enabling students to track Regular, Mid-term, and Final grades across semesters. Features include bonus point management, detailed grade reasoning, and automatic TBM (Average) calculation."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Semester = 1 | 2;

export enum GradeType {
  REGULAR = 'REGULAR', // Hệ số 1 (Thường xuyên)
  MIDTERM = 'MIDTERM', // Hệ số 2 (Giữa kì)
  FINAL = 'FINAL',     // Hệ số 3 (Cuối kì)
}

export interface Grade {
  id: string;
  value: number;
  reason: string; // Lí do có điểm
  timestamp: number;
}

export interface BonusPoint {
  id: string;
  value: number;
  reason: string;
  timestamp: number;
}

export interface SubjectData {
  id: string;
  name: string;
  regularGrades: Grade[];
  midtermGrade: Grade | null;
  finalGrade: Grade | null;
  bonusPoints: BonusPoint[]; // Kho điểm cộng
}

export interface AppState {
  subjectsSem1: SubjectData[];
  subjectsSem2: SubjectData[];
}

export const STORAGE_KEY = 'grademaster_data_v1';

export const COLORS = {
  primary: '#4f46e5', // Indigo 600
  success: '#10b981', // Emerald 500
  warning: '#f59e0b', // Amber 500
  danger: '#ef4444',  // Red 500
  gray: '#6b7280',
};

// Coefficient weights
export const WEIGHTS = {
  REGULAR: 1,
  MIDTERM: 2,
  FINAL: 3,
};

import { AppState, SubjectData, Semester } from '../types';
import { STORAGE_KEY } from '../constants';

export const loadData = (): AppState => {
  try {
    const serialized = localStorage.getItem(STORAGE_KEY);
    if (serialized) {
      return JSON.parse(serialized);
    }
  } catch (e) {
    console.error("Failed to load data", e);
  }
  return {
    subjectsSem1: [],
    subjectsSem2: [],
  };
};

export const saveData = (data: AppState) => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
  } catch (e) {
    console.error("Failed to save data", e);
  }
};

export const exportToCSV = (data: AppState, semester: Semester) => {
  const subjects = semester === 1 ? data.subjectsSem1 : data.subjectsSem2;

  // Header
  let csvContent = "data:text/csv;charset=utf-8,";
  csvContent += "Môn Học,Điểm Thường Xuyên,Điểm Giữa Kì,Điểm Cuối Kì,Điểm Cộng Còn Lại,Trung Bình Môn\n";

  subjects.forEach(sub => {
    const regular = sub.regularGrades.map(g => `${g.value} (${g.reason})`).join("; ");
    const midterm = sub.midtermGrade ? `${sub.midtermGrade.value} (${sub.midtermGrade.reason})` : "";
    const final = sub.finalGrade ? `${sub.finalGrade.value} (${sub.finalGrade.reason})` : "";

    // Calculate TBM for export
    const regSum = sub.regularGrades.reduce((sum, g) => sum + g.value, 0);
    const midVal = sub.midtermGrade ? sub.midtermGrade.value : 0;
    const finalVal = sub.finalGrade ? sub.finalGrade.value : 0;
    const countReg = sub.regularGrades.length;

    // Formula: (RegSum + Mid*2 + Final*3) / (CountReg + 5)
    // Note: Only calculate if Mid and Final exist for accuracy, otherwise partial
    let tbm = "N/A";
    if (sub.midtermGrade && sub.finalGrade) {
        const val = (regSum + (midVal * 2) + (finalVal * 3)) / (countReg + 5);
        tbm = val.toFixed(2);
    }

    const bonusTotal = sub.bonusPoints.reduce((sum, b) => sum + b.value, 0);

    const row = [
      `"${sub.name}"`,
      `"${regular}"`,
      `"${midterm}"`,
      `"${final}"`,
      `"${bonusTotal}"`,
      `"${tbm}"`
    ].join(",");
    csvContent += row + "\r\n";
  });

  const encodedUri = encodeURI(csvContent);
  const link = document.createElement("a");
  link.setAttribute("href", encodedUri);
  link.setAttribute("download", `bang_diem_ki_${semester}.csv`);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { AppState, SubjectData, Semester, Grade, GradeType, BonusPoint } from '../types';
import { loadData, saveData } from '../services/storageService';
import { v4 as uuidv4 } from 'uuid';

interface GradeContextType {
  semester: Semester;
  setSemester: (sem: Semester) => void;
  subjects: SubjectData[];
  addSubject: (name: string) => void;
  deleteSubject: (id: string) => void;
  addGrade: (subjectId: string, type: GradeType, value: number, reason: string) => void;
  updateGrade: (subjectId: string, gradeId: string, type: GradeType, newValue: number, newReason: string) => void;
  deleteGrade: (subjectId: string, gradeId: string, type: GradeType) => void;
  addBonusPoint: (subjectId: string, value: number, reason: string) => void;
  useBonusPoint: (subjectId: string, gradeId: string, gradeType: GradeType, bonusAmount: number) => boolean;
}

const GradeContext = createContext<GradeContextType | undefined>(undefined);

export const GradeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [data, setData] = useState<AppState>({ subjectsSem1: [], subjectsSem2: [] });
  const [semester, setSemester] = useState<Semester>(1);

  // Initial load
  useEffect(() => {
    const loaded = loadData();
    setData(loaded);
  }, []);

  // Save on change
  useEffect(() => {
    saveData(data);
  }, [data]);

  const currentSubjects = semester === 1 ? data.subjectsSem1 : data.subjectsSem2;

  const updateSubjects = useCallback((newSubjects: SubjectData[]) => {
    setData(prev => ({
      ...prev,
      [semester === 1 ? 'subjectsSem1' : 'subjectsSem2']: newSubjects
    }));
  }, [semester]);

  const addSubject = (name: string) => {
    const newSubject: SubjectData = {
      id: uuidv4(),
      name,
      regularGrades: [],
      midtermGrade: null,
      finalGrade: null,
      bonusPoints: []
    };
    updateSubjects([...currentSubjects, newSubject]);
  };

  const deleteSubject = (id: string) => {
    updateSubjects(currentSubjects.filter(s => s.id !== id));
  };

  const addGrade = (subjectId: string, type: GradeType, value: number, reason: string) => {
    const newGrade: Grade = {
      id: uuidv4(),
      value,
      reason,
      timestamp: Date.now()
    };

    const newSubjects = currentSubjects.map(sub => {
      if (sub.id !== subjectId) return sub;
      if (type === GradeType.REGULAR) {
        return { ...sub, regularGrades: [...sub.regularGrades, newGrade] };
      } else if (type === GradeType.MIDTERM) {
        return { ...sub, midtermGrade: newGrade };
      } else {
        return { ...sub, finalGrade: newGrade };
      }
    });
    updateSubjects(newSubjects);
  };

  const updateGrade = (subjectId: string, gradeId: string, type: GradeType, newValue: number, newReason: string) => {
    const newSubjects = currentSubjects.map(sub => {
      if (sub.id !== subjectId) return sub;

      if (type === GradeType.REGULAR) {
        return {
          ...sub,
          regularGrades: sub.regularGrades.map(g => g.id === gradeId ? { ...g, value: newValue, reason: newReason } : g)
        };
      } else if (type === GradeType.MIDTERM && sub.midtermGrade?.id === gradeId) {
        return { ...sub, midtermGrade: { ...sub.midtermGrade, value: newValue, reason: newReason } };
      } else if (type === GradeType.FINAL && sub.finalGrade?.id === gradeId) {
        return { ...sub, finalGrade: { ...sub.finalGrade, value: newValue, reason: newReason } };
      }
      return sub;
    });
    updateSubjects(newSubjects);
  };

  const deleteGrade = (subjectId: string, gradeId: string, type: GradeType) => {
     const newSubjects = currentSubjects.map(sub => {
      if (sub.id !== subjectId) return sub;

      if (type === GradeType.REGULAR) {
        return { ...sub, regularGrades: sub.regularGrades.filter(g => g.id !== gradeId) };
      } else if (type === GradeType.MIDTERM && sub.midtermGrade?.id === gradeId) {
        return { ...sub, midtermGrade: null };
      } else if (type === GradeType.FINAL && sub.finalGrade?.id === gradeId) {
        return { ...sub, finalGrade: null };
      }
      return sub;
    });
    updateSubjects(newSubjects);
  };

  const addBonusPoint = (subjectId: string, value: number, reason: string) => {
    const newBonus: BonusPoint = { id: uuidv4(), value, reason, timestamp: Date.now() };
    const newSubjects = currentSubjects.map(sub => {
      if (sub.id !== subjectId) return sub;
      return { ...sub, bonusPoints: [...sub.bonusPoints, newBonus] };
    });
    updateSubjects(newSubjects);
  };

  const useBonusPoint = (subjectId: string, gradeId: string, gradeType: GradeType, bonusAmount: number): boolean => {
    // This function attempts to deduct bonus points from the bank and apply to a grade
    // Note: It simplifies by just removing *any* combination of bonus points that sum up or reducing a single large one.
    // To keep it simple for this app: We just deduct the total value from the "Bank" (conceptually).
    // Implementation: We will reduce the value of existing bonus points or remove them until `bonusAmount` is satisfied.

    // 1. Check if enough points
    const subject = currentSubjects.find(s => s.id === subjectId);
    if (!subject) return false;

    const totalBonus = subject.bonusPoints.reduce((sum, b) => sum + b.value, 0);
    if (totalBonus < bonusAmount) return false;

    // 2. Consume points (FIFO or largest first? Let's just consume value)
    let remainingToConsume = bonusAmount;
    let newBonusPoints = [...subject.bonusPoints];

    // Sort logic could go here, but simple iteration is fine
    // We iterate and reduce/remove
    newBonusPoints = newBonusPoints.map(bp => {
        if (remainingToConsume <= 0) return bp;

        if (bp.value <= remainingToConsume) {
            remainingToConsume -= bp.value;
            return { ...bp, value: 0 }; // Mark for removal
        } else {
            const newVal = bp.value - remainingToConsume;
            remainingToConsume = 0;
            return { ...bp, value: newVal };
        }
    }).filter(bp => bp.value > 0);

    // 3. Update Grade
    let updatedRegular = subject.regularGrades;
    let updatedMid = subject.midtermGrade;
    let updatedFinal = subject.finalGrade;

    const appendReason = ` (+${bonusAmount} điểm cộng)`;

    if (gradeType === GradeType.REGULAR) {
        updatedRegular = updatedRegular.map(g => g.id === gradeId ? { ...g, value: g.value + bonusAmount, reason: g.reason + appendReason } : g);
    } else if (gradeType === GradeType.MIDTERM && updatedMid?.id === gradeId) {
        updatedMid = { ...updatedMid, value: updatedMid.value + bonusAmount, reason: updatedMid.reason + appendReason };
    } else if (gradeType === GradeType.FINAL && updatedFinal?.id === gradeId) {
        updatedFinal = { ...updatedFinal, value: updatedFinal.value + bonusAmount, reason: updatedFinal.reason + appendReason };
    }

    const newSubjects = currentSubjects.map(sub => {
        if (sub.id !== subjectId) return sub;
        return {
            ...sub,
            bonusPoints: newBonusPoints,
            regularGrades: updatedRegular,
            midtermGrade: updatedMid,
            finalGrade: updatedFinal
        };
    });
    updateSubjects(newSubjects);
    return true;
  };

  return (
    <GradeContext.Provider value={{ 
      semester, 
      setSemester, 
      subjects: currentSubjects, 
      addSubject, 
      deleteSubject,
      addGrade,
      updateGrade,
      deleteGrade,
      addBonusPoint,
      useBonusPoint
    }}>
      {children}
    </GradeContext.Provider>
  );
};

export const useGrade = () => {
  const context = useContext(GradeContext);
  if (!context) throw new Error("useGrade must be used within a GradeProvider");
  return context;
};

import React, { useState } from 'react';
import { X, PlusCircle } from 'lucide-react';

interface BonusModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (value: number, reason: string) => void;
  subjectName: string;
}

const BonusModal: React.FC<BonusModalProps> = ({ isOpen, onClose, onSave, subjectName }) => {
  const [value, setValue] = useState<string>('0.5');
  const [reason, setReason] = useState('');

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const numVal = parseFloat(value);
    if (!isNaN(numVal) && numVal > 0 && reason.trim()) {
      onSave(numVal, reason);
      setReason('');
      setValue('0.5');
      onClose();
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden animate-fade-in-up">
        <div className="bg-indigo-600 px-6 py-4 flex justify-between items-center">
          <h3 className="text-white font-semibold text-lg">Thêm Điểm Cộng: {subjectName}</h3>
          <button onClick={onClose} className="text-white hover:bg-indigo-700 p-1 rounded-full transition">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Số điểm cộng</label>
            <input
              type="number"
              step="0.1"
              max="10"
              min="0.1"
              value={value}
              onChange={(e) => setValue(e.target.value)}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition"
              autoFocus
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Lí do / Nguồn gốc</label>
            <input
              type="text"
              value={reason}
              onChange={(e) => setReason(e.target.value)}
              placeholder="Vd: Phát biểu đúng, Làm bài tập về nhà..."
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition"
            />
          </div>

          <div className="pt-2 flex justify-end gap-3">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-2 text-gray-700 hover:bg-gray-100 rounded-lg transition"
            >
              Hủy
            </button>
            <button
              type="submit"
              disabled={!reason.trim()}
              className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition disabled:opacity-50 disabled:cursor-not-allowed"
            >
              <PlusCircle size={18} />
              Lưu vào kho
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default BonusModal;

import React, { useState, useEffect } from 'react';
import { X, Save, Trash2, Wand2 } from 'lucide-react';
import { Grade, GradeType } from '../types';

interface GradeInputModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (value: number, reason: string) => void;
  onDelete?: () => void;
  onUseBonus?: (amount: number) => void;
  initialData?: Grade | null;
  gradeType: GradeType;
  subjectName: string;
  maxBonusAvailable: number;
}

const GradeInputModal: React.FC<GradeInputModalProps> = ({ 
  isOpen, onClose, onSave, onDelete, onUseBonus, initialData, gradeType, subjectName, maxBonusAvailable 
}) => {
  const [value, setValue] = useState<string>('');
  const [reason, setReason] = useState('');
  const [bonusToUse, setBonusToUse] = useState<string>('0');
  const [showBonusInput, setShowBonusInput] = useState(false);

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setValue(initialData.value.toString());
        setReason(initialData.reason);
      } else {
        setValue('');
        setReason('');
      }
      setShowBonusInput(false);
      setBonusToUse('0');
    }
  }, [isOpen, initialData]);

  if (!isOpen) return null;

  const getTitle = () => {
    const typeMap = {
      [GradeType.REGULAR]: 'Thường Xuyên',
      [GradeType.MIDTERM]: 'Giữa Kì (x2)',
      [GradeType.FINAL]: 'Cuối Kì (x3)',
    };
    return initialData ? `Sửa Điểm ${typeMap[gradeType]}` : `Nhập Điểm ${typeMap[gradeType]}`;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const numVal = parseFloat(value);
    if (!isNaN(numVal) && numVal >= 0 && numVal <= 10 && reason.trim()) {
      onSave(numVal, reason);
      onClose();
    }
  };

  const handleApplyBonus = () => {
    const amount = parseFloat(bonusToUse);
    if (onUseBonus && !isNaN(amount) && amount > 0 && amount <= maxBonusAvailable) {
        onUseBonus(amount);
        onClose();
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden animate-fade-in-up">
        <div className="bg-indigo-600 px-6 py-4 flex justify-between items-center">
          <div>
            <h3 className="text-white font-semibold text-lg">{getTitle()}</h3>
            <p className="text-indigo-200 text-xs">{subjectName}</p>
          </div>
          <button onClick={onClose} className="text-white hover:bg-indigo-700 p-1 rounded-full transition">
            <X size={20} />
          </button>
        </div>

        <div className="p-6">
          {!showBonusInput ? (
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Điểm số (0-10)</label>
                <input
                  type="number"
                  step="0.01"
                  max="10"
                  min="0"
                  value={value}
                  onChange={(e) => setValue(e.target.value)}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition text-lg font-mono"
                  autoFocus
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Lí do có điểm</label>
                <textarea
                  value={reason}
                  onChange={(e) => setReason(e.target.value)}
                  placeholder="Vd: Kiểm tra 15p, Thi viết, ..."
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition h-24 resize-none"
                  required
                />
              </div>

              <div className="flex justify-between items-center pt-2">
                <div>
                   {initialData && onDelete && (
                    <button
                        type="button"
                        onClick={() => {
                            if(window.confirm('Bạn có chắc chắn muốn xóa điểm này?')) {
                                onDelete();
                                onClose();
                            }
                        }}
                        className="text-red-500 hover:text-red-700 text-sm flex items-center gap-1 px-2 py-1 hover:bg-red-50 rounded"
                    >
                        <Trash2 size={16} /> Xóa
                    </button>
                   )}
                </div>
                <div className="flex gap-2">
                   {initialData && maxBonusAvailable > 0 && (
                        <button
                            type="button"
                            onClick={() => setShowBonusInput(true)}
                            className="bg-amber-100 text-amber-700 hover:bg-amber-200 px-3 py-2 rounded-lg text-sm font-medium flex items-center gap-1 transition"
                        >
                            <Wand2 size={16} /> Bù điểm
                        </button>
                   )}
                    <button
                        type="submit"
                        disabled={!value || !reason.trim()}
                        className="bg-indigo-600 text-white hover:bg-indigo-700 px-4 py-2 rounded-lg flex items-center gap-2 transition disabled:opacity-50"
                    >
                        <Save size={18} /> Lưu
                    </button>
                </div>
              </div>
            </form>
          ) : (
            <div className="space-y-4 animate-fade-in">
                 <div className="bg-amber-50 border border-amber-200 rounded-lg p-3">
                    <p className="text-amber-800 text-sm font-medium">Kho điểm cộng: {maxBonusAvailable.toFixed(2)}</p>
                    <p className="text-amber-600 text-xs mt-1">Sử dụng điểm cộng để tăng điểm số hiện tại ({value}).</p>
                 </div>

                 <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Cộng thêm bao nhiêu?</label>
                    <input
                        type="number"
                        step="0.1"
                        max={maxBonusAvailable}
                        min="0.1"
                        value={bonusToUse}
                        onChange={(e) => setBonusToUse(e.target.value)}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 transition"
                    />
                 </div>

                 <div className="flex justify-end gap-2 pt-2">
                    <button 
                        onClick={() => setShowBonusInput(false)}
                        className="text-gray-600 hover:bg-gray-100 px-3 py-2 rounded-lg"
                    >
                        Quay lại
                    </button>
                    <button
                        onClick={handleApplyBonus}
                        disabled={parseFloat(bonusToUse) <= 0 || parseFloat(bonusToUse) > maxBonusAvailable}
                        className="bg-amber-500 text-white hover:bg-amber-600 px-4 py-2 rounded-lg flex items-center gap-1 disabled:opacity-50 transition"
                    >
                        <Wand2 size={16} /> Xác nhận bù
                    </button>
                 </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default GradeInputModal;

import React, { useState } from 'react';
import { SubjectData, Grade, GradeType } from '../types';
import { useGrade } from '../context/GradeContext';
import { Plus, Edit2, Database } from 'lucide-react';
import GradeInputModal from './GradeInputModal';
import BonusModal from './BonusModal';

const GradeChip: React.FC<{ 
    grade: Grade; 
    onClick: () => void; 
    colorClass: string 
}> = ({ grade, onClick, colorClass }) => (
  <button
    onClick={onClick}
    className={`${colorClass} px-3 py-1 rounded-full text-sm font-bold shadow-sm hover:shadow-md transition transform hover:-translate-y-0.5 border border-opacity-20 flex items-center gap-1 group`}
    title={grade.reason}
  >
    {grade.value}
    <span className="hidden group-hover:inline text-[10px] opacity-75 font-normal ml-1 truncate max-w-[60px]">
        {grade.reason}
    </span>
  </button>
);

const EmptySlot: React.FC<{ onClick: () => void; label?: string }> = ({ onClick, label }) => (
  <button
    onClick={onClick}
    className="w-8 h-8 rounded-full border-2 border-dashed border-gray-300 hover:border-indigo-500 hover:bg-indigo-50 text-gray-300 hover:text-indigo-500 flex items-center justify-center transition"
    title={label || "Thêm điểm"}
  >
    <Plus size={16} />
  </button>
);

const SubjectRow: React.FC<{ subject: SubjectData }> = ({ subject }) => {
  const { addGrade, updateGrade, deleteGrade, addBonusPoint, useBonusPoint, deleteSubject } = useGrade();

  const [modalOpen, setModalOpen] = useState(false);
  const [bonusModalOpen, setBonusModalOpen] = useState(false);
  const [editingGrade, setEditingGrade] = useState<{ id: string, type: GradeType } | null>(null);
  const [targetType, setTargetType] = useState<GradeType>(GradeType.REGULAR);

  // Calculate TBM
  const regSum = subject.regularGrades.reduce((sum, g) => sum + g.value, 0);
  const midVal = subject.midtermGrade ? subject.midtermGrade.value : 0;
  const finalVal = subject.finalGrade ? subject.finalGrade.value : 0;
  const countReg = subject.regularGrades.length;

  // Formula: (Reg + Mid*2 + Final*3) / (CountReg + 5)
  // We display TBM only if we have at least some data, but technically the formula requires all to be accurate.
  // We will calc based on what exists for "Current" progress, but highlight if incomplete.

  const denominator = countReg + 5;
  const numerator = regSum + (midVal * 2) + (finalVal * 3);
  const tbm = numerator / denominator;

  const isComplete = subject.midtermGrade !== null && subject.finalGrade !== null;
  const displayTbm = tbm.toFixed(2);

  const totalBonus = subject.bonusPoints.reduce((sum, b) => sum + b.value, 0);

  // Grade color logic
  const getColor = (val: number) => {
    if (val >= 8.0) return 'bg-emerald-100 text-emerald-800 border-emerald-500';
    if (val >= 6.5) return 'bg-blue-100 text-blue-800 border-blue-500';
    if (val >= 5.0) return 'bg-amber-100 text-amber-800 border-amber-500';
    return 'bg-red-100 text-red-800 border-red-500';
  };

  const handleOpenAdd = (type: GradeType) => {
    setEditingGrade(null);
    setTargetType(type);
    setModalOpen(true);
  };

  const handleOpenEdit = (grade: Grade, type: GradeType) => {
    setEditingGrade({ id: grade.id, type });
    setTargetType(type);
    setModalOpen(true);
  };

  const getInitialData = () => {
    if (!editingGrade) return null;
    if (editingGrade.type === GradeType.REGULAR) {
        return subject.regularGrades.find(g => g.id === editingGrade.id) || null;
    }
    if (editingGrade.type === GradeType.MIDTERM) return subject.midtermGrade;
    if (editingGrade.type === GradeType.FINAL) return subject.finalGrade;
    return null;
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5 mb-4 hover:shadow-md transition duration-200">
      <div className="flex flex-col md:flex-row gap-6">

        {/* Subject Info & Stats */}
        <div className="w-full md:w-1/4 flex flex-col justify-between border-b md:border-b-0 md:border-r border-gray-100 pb-4 md:pb-0 md:pr-4">
          <div>
            <div className="flex justify-between items-start">
              <h3 className="font-bold text-lg text-gray-800">{subject.name}</h3>
              <button 
                onClick={() => { if(window.confirm(`Xóa môn ${subject.name}?`)) deleteSubject(subject.id); }}
                className="text-gray-400 hover:text-red-500 transition"
              >
                <span className="sr-only">Xóa môn</span>
                <XIcon size={16} />
              </button>
            </div>
            <div className="mt-3 flex items-center gap-2 text-sm text-gray-600 bg-gray-50 p-2 rounded-lg cursor-pointer hover:bg-indigo-50 transition" onClick={() => setBonusModalOpen(true)}>
                <Database size={14} className="text-indigo-500" />
                <span>Kho điểm cộng: <span className="font-bold text-indigo-600">{totalBonus.toFixed(1)}</span></span>
                <Plus size={14} className="ml-auto text-gray-400" />
            </div>
          </div>

          <div className="mt-4">
             <div className="text-xs text-gray-500 uppercase font-semibold tracking-wider mb-1">Trung Bình Môn</div>
             <div className={`text-3xl font-bold ${getColor(tbm).replace('bg-', 'text-').split(' ')[1]}`}>
                {displayTbm}
                {!isComplete && <span className="text-xs text-gray-400 font-normal ml-1 align-top">(Tạm tính)</span>}
             </div>
          </div>
        </div>

        {/* Grades Area */}
        <div className="flex-1 grid grid-cols-1 md:grid-cols-12 gap-4">

            {/* Regular Grades */}
            <div className="md:col-span-6 space-y-2">
                <div className="text-xs font-semibold text-gray-400 uppercase">Thường Xuyên (Hệ số 1)</div>
                <div className="flex flex-wrap gap-2">
                    {subject.regularGrades.map(g => (
                        <GradeChip 
                            key={g.id} 
                            grade={g} 
                            colorClass={getColor(g.value)} 
                            onClick={() => handleOpenEdit(g, GradeType.REGULAR)} 
                        />
                    ))}
                    <EmptySlot onClick={() => handleOpenAdd(GradeType.REGULAR)} />
                </div>
            </div>

            {/* Midterm */}
            <div className="md:col-span-3 space-y-2">
                <div className="text-xs font-semibold text-gray-400 uppercase">Giữa Kì (Hệ số 2)</div>
                <div>
                    {subject.midtermGrade ? (
                        <GradeChip 
                            grade={subject.midtermGrade} 
                            colorClass={getColor(subject.midtermGrade.value)} 
                            onClick={() => handleOpenEdit(subject.midtermGrade!, GradeType.MIDTERM)} 
                        />
                    ) : (
                        <EmptySlot onClick={() => handleOpenAdd(GradeType.MIDTERM)} label="Nhập giữa kì" />
                    )}
                </div>
            </div>

            {/* Final */}
            <div className="md:col-span-3 space-y-2">
                <div className="text-xs font-semibold text-gray-400 uppercase">Cuối Kì (Hệ số 3)</div>
                 <div>
                    {subject.finalGrade ? (
                        <GradeChip 
                            grade={subject.finalGrade} 
                            colorClass={getColor(subject.finalGrade.value)} 
                            onClick={() => handleOpenEdit(subject.finalGrade!, GradeType.FINAL)} 
                        />
                    ) : (
                        <EmptySlot onClick={() => handleOpenAdd(GradeType.FINAL)} label="Nhập cuối kì" />
                    )}
                </div>
            </div>

        </div>
      </div>

      <GradeInputModal 
        isOpen={modalOpen}
        onClose={() => setModalOpen(false)}
        gradeType={targetType}
        subjectName={subject.name}
        initialData={getInitialData()}
        maxBonusAvailable={totalBonus}
        onSave={(val, reason) => {
            if (editingGrade) {
                updateGrade(subject.id, editingGrade.id, targetType, val, reason);
            } else {
                addGrade(subject.id, targetType, val, reason);
            }
        }}
        onDelete={() => {
            if (editingGrade) {
                deleteGrade(subject.id, editingGrade.id, targetType);
            }
        }}
        onUseBonus={(amount) => {
            if (editingGrade) {
                useBonusPoint(subject.id, editingGrade.id, targetType, amount);
            }
        }}
      />

      <BonusModal
        isOpen={bonusModalOpen}
        onClose={() => setBonusModalOpen(false)}
        subjectName={subject.name}
        onSave={(val, reason) => addBonusPoint(subject.id, val, reason)}
      />
    </div>
  );
};

