import { AppState } from '../types';

export interface SyncResponse {
  success: boolean;
  message?: string;
  data?: AppState;
}

export const syncToSheet = async (url: string, data: AppState): Promise<SyncResponse> => {
  try {
    // Google Apps Script Web App requests require 'no-cors' for simple POSTs or proper CORS handling.
    // Standard fetch with CORS mode usually works if the script returns ContentService.createTextOutput with setMimeType(ContentService.MimeType.JSON)
    const response = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'text/plain;charset=utf-8', // Use text/plain to avoid preflight OPTIONS check issues with GAS
      },
      body: JSON.stringify({
        action: 'save',
        data: data
      })
    });

    const result = await response.json();
    return result;
  } catch (error) {
    console.error("Sync error:", error);
    return { success: false, message: 'Lỗi kết nối đến Google Sheet' };
  }
};

export const loadFromSheet = async (url: string): Promise<SyncResponse> => {
  try {
    // Adding a timestamp to prevent caching
    const fetchUrl = `${url}?action=load&t=${Date.now()}`;
    const response = await fetch(fetchUrl);
    const result = await response.json();
    return result;
  } catch (error) {
    console.error("Load error:", error);
    return { success: false, message: 'Không thể tải dữ liệu từ Google Sheet' };
  }
};

import { AppState, Semester } from '../types';
import { STORAGE_KEY } from '../constants';

const CONFIG_KEY = 'grademaster_config_v1';

export const loadData = (): AppState => {
  try {
    const serialized = localStorage.getItem(STORAGE_KEY);
    if (serialized) {
      return JSON.parse(serialized);
    }
  } catch (e) {
    console.error("Failed to load data", e);
  }
  return {
    subjectsSem1: [],
    subjectsSem2: [],
  };
};

export const saveData = (data: AppState) => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
  } catch (e) {
    console.error("Failed to save data", e);
  }
};

export const saveConfig = (url: string) => {
    localStorage.setItem(CONFIG_KEY, JSON.stringify({ sheetUrl: url }));
};

export const loadConfig = (): { sheetUrl: string } => {
    try {
        const conf = localStorage.getItem(CONFIG_KEY);
        if (conf) return JSON.parse(conf);
    } catch (e) {}
    return { sheetUrl: '' };
};

export const exportToCSV = (data: AppState, semester: Semester) => {
  const subjects = semester === 1 ? data.subjectsSem1 : data.subjectsSem2;

  // Header
  let csvContent = "data:text/csv;charset=utf-8,";
  csvContent += "Môn Học,Điểm Thường Xuyên,Điểm Giữa Kì,Điểm Cuối Kì,Điểm Cộng Còn Lại,Trung Bình Môn\n";

  subjects.forEach(sub => {
    const regular = sub.regularGrades.map(g => `${g.value} (${g.reason})`).join("; ");
    const midterm = sub.midtermGrade ? `${sub.midtermGrade.value} (${sub.midtermGrade.reason})` : "";
    const final = sub.finalGrade ? `${sub.finalGrade.value} (${sub.finalGrade.reason})` : "";

    // Calculate TBM for export
    const regSum = sub.regularGrades.reduce((sum, g) => sum + g.value, 0);
    const midVal = sub.midtermGrade ? sub.midtermGrade.value : 0;
    const finalVal = sub.finalGrade ? sub.finalGrade.value : 0;
    const countReg = sub.regularGrades.length;

    // Formula: (RegSum + Mid*2 + Final*3) / (CountReg + 5)
    let tbm = "N/A";
    if (sub.midtermGrade && sub.finalGrade) {
        const val = (regSum + (midVal * 2) + (finalVal * 3)) / (countReg + 5);
        tbm = val.toFixed(2);
    }

    const bonusTotal = sub.bonusPoints.reduce((sum, b) => sum + b.value, 0);

    const row = [
      `"${sub.name}"`,
      `"${regular}"`,
      `"${midterm}"`,
      `"${final}"`,
      `"${bonusTotal}"`,
      `"${tbm}"`
    ].join(",");
    csvContent += row + "\r\n";
  });

  const encodedUri = encodeURI(csvContent);
  const link = document.createElement("a");
  link.setAttribute("href", encodedUri);
  link.setAttribute("download", `bang_diem_ki_${semester}.csv`);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

