### Hướng dẫn Set up Google Sheet làm Database

Để ứng dụng này lưu được điểm vào Google Sheet của bạn, hãy làm theo các bước sau:

**Bước 1: Tạo Google Sheet và Script**
1.  Truy cập [Google Sheets](https://sheets.new) để tạo một bảng tính mới.
2.  Đặt tên tùy thích (Ví dụ: "Database Điểm Số").
3.  Trên menu, chọn **Extensions (Tiện ích mở rộng)** > **Apps Script**.
4.  Xóa hết mã cũ trong file `Code.gs` và dán toàn bộ đoạn mã sau vào:

```javascript
function doGet(e) {
  return handleRequest(e);
}

function doPost(e) {
  return handleRequest(e);
}

function handleRequest(e) {
  var lock = LockService.getScriptLock();
  lock.tryLock(10000);

  try {
    var doc = SpreadsheetApp.getActiveSpreadsheet();
    var dbSheet = doc.getSheetByName("DB_RAW");

    // Nếu chưa có sheet lưu JSON thô thì tạo mới
    if (!dbSheet) {
      dbSheet = doc.insertSheet("DB_RAW");
      dbSheet.hideSheet(); // Ẩn đi để đỡ rối
    }

    var action = e.parameter.action;

    // Nếu là POST request, thường dữ liệu nằm trong e.postData.contents
    if (e.postData && e.postData.contents) {
      var body = JSON.parse(e.postData.contents);
      action = body.action;
      var data = body.data;
    }

    if (action === "save") {
      // 1. Lưu JSON thô vào ô A1 của sheet DB_RAW
      dbSheet.getRange(1, 1).setValue(JSON.stringify(data));

      // 2. (Tùy chọn) Xuất ra Sheet đẹp để bạn xem
      exportToReadableSheet(doc, data);

      return response({ success: true, message: "Saved successfully" });
    } 
    else if (action === "load" || !action) {
      // Tải dữ liệu từ ô A1
      var json = dbSheet.getRange(1, 1).getValue();
      var data = json ? JSON.parse(json) : { subjectsSem1: [], subjectsSem2: [] };
      return response({ success: true, data: data });
    }

  } catch (err) {
    return response({ success: false, message: err.toString() });
  } finally {
    lock.releaseLock();
  }
}

function response(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

// Hàm hỗ trợ xuất dữ liệu ra bảng đẹp để bạn xem trực tiếp trên Sheet
function exportToReadableSheet(doc, data) {
  updateSemesterSheet(doc, "Học Kì 1", data.subjectsSem1);
  updateSemesterSheet(doc, "Học Kì 2", data.subjectsSem2);
}

function updateSemesterSheet(doc, sheetName, subjects) {
  var sheet = doc.getSheetByName(sheetName);
  if (!sheet) sheet = doc.insertSheet(sheetName);

  sheet.clear();
  // Header
  sheet.appendRow(["Môn Học", "Điểm Thường Xuyên", "Giữa Kì", "Cuối Kì", "Điểm Cộng Dư", "Trung Bình Môn"]);

  // Format Header
  sheet.getRange(1, 1, 1, 6).setFontWeight("bold").setBackground("#e0e0e0");

  if (!subjects || subjects.length === 0) return;

  var rows = subjects.map(function(sub) {
    var reg = sub.regularGrades.map(g => g.value).join(", ");
    var mid = sub.midtermGrade ? sub.midtermGrade.value : "";
    var final = sub.finalGrade ? sub.finalGrade.value : "";
    var bonus = sub.bonusPoints.reduce((sum, b) => sum + b.value, 0);

    // Tính TBM
    var regSum = sub.regularGrades.reduce((sum, g) => sum + g.value, 0);
    var midVal = sub.midtermGrade ? sub.midtermGrade.value : 0;
    var finalVal = sub.finalGrade ? sub.finalGrade.value : 0;
    var countReg = sub.regularGrades.length;
    var tbm = "";

    if (sub.midtermGrade && sub.finalGrade) {
        tbm = ((regSum + midVal*2 + finalVal*3) / (countReg + 5)).toFixed(2);
    }

    return [sub.name, reg, mid, final, bonus, tbm];
  });

  if (rows.length > 0) {
    sheet.getRange(2, 1, rows.length, 6).setValues(rows);
  }
}
```

**Bước 2: Triển khai (Deploy)**
1.  Trong cửa sổ Apps Script, nhấn nút **Deploy (Triển khai)** màu xanh ở góc trên bên phải > chọn **New deployment**.
2.  Bấm vào biểu tượng bánh răng (Select type) > chọn **Web app**.
3.  Điền thông tin:
    *   **Description**: GradeMaster API (tùy ý).
    *   **Execute as**: Me (tài khoản của bạn).
    *   **Who has access**: **Anyone (Bất kỳ ai)**. *Lưu ý: Phải chọn Anyone để ứng dụng web không cần đăng nhập Google vẫn ghi được dữ liệu.*
4.  Nhấn **Deploy**.
5.  Copy **Web App URL** (đường dẫn bắt đầu bằng `https://script.google.com/macros/s/...`).

**Bước 3: Kết nối**
1.  Quay lại ứng dụng web GradeMaster của bạn.
2.  Bấm vào biểu tượng **Cài đặt (Bánh răng)** trên thanh Header.
3.  Dán URL vừa copy vào ô **Web App URL**.
4.  Bấm **Lưu Cấu Hình**.

Lúc này, mỗi khi bạn sửa điểm, ứng dụng sẽ tự động (sau 3 giây) gửi dữ liệu lên Google Sheet của bạn. Bạn có thể mở Sheet ra để xem tab "Học Kì 1" và "Học Kì 2" được cập nhật tự động.

