  const { addGrade, updateGrade, deleteGrade, addBonusPoint, useBonusPoint, deleteSubject } = useGrade();

  const [modalOpen, setModalOpen] = useState(false);
  const [bonusModalOpen, setBonusModalOpen] = useState(false);
  const [editingGrade, setEditingGrade] = useState<{ id: string, type: GradeType } | null>(null);
  const [targetType, setTargetType] = useState<GradeType>(GradeType.REGULAR);

  // Calculate TBM (Average)
  // Dynamic Formula:
  // 1. Regular only: Sum(Reg) / Count(Reg)
  // 2. Regular + Mid: (Sum(Reg) + Mid*2) / (Count(Reg) + 2)
  // 3. Full: (Sum(Reg) + Mid*2 + Final*3) / (Count(Reg) + 5)

  const regSum = subject.regularGrades.reduce((sum, g) => sum + g.value, 0);
  const countReg = subject.regularGrades.length;
  const midVal = subject.midtermGrade ? subject.midtermGrade.value : 0;
  const finalVal = subject.finalGrade ? subject.finalGrade.value : 0;

  let numerator = 0;
  let denominator = 0;
  let displayTbm = "---";
  let tbmValue = 0;

  if (countReg > 0 || subject.midtermGrade || subject.finalGrade) {
      // Add Regular
      numerator += regSum;
      denominator += countReg;

      // Add Midterm (Weight 2)
      if (subject.midtermGrade) {
          numerator += midVal * 2;
          denominator += 2;
      }

      // Add Final (Weight 3)
      if (subject.finalGrade) {
          numerator += finalVal * 3;
          denominator += 3;
      }

      if (denominator > 0) {
          tbmValue = numerator / denominator;
          displayTbm = tbmValue.toFixed(2);
      }
  }

  const totalBonus = subject.bonusPoints.reduce((sum, b) => sum + b.value, 0);

  // Grade color logic
  const getColor = (val: number) => {
    if (val >= 8.0) return 'bg-emerald-100 text-emerald-800 border-emerald-500';
    if (val >= 6.5) return 'bg-blue-100 text-blue-800 border-blue-500';
    if (val >= 5.0) return 'bg-amber-100 text-amber-800 border-amber-500';
    return 'bg-red-100 text-red-800 border-red-500';
  };

  const handleOpenAdd = (type: GradeType) => {
    setEditingGrade(null);
    setTargetType(type);
    setModalOpen(true);
  };

  const handleOpenEdit = (grade: Grade, type: GradeType) => {
    setEditingGrade({ id: grade.id, type });
    setTargetType(type);
    setModalOpen(true);
  };

  const getInitialData = () => {
    if (!editingGrade) return null;
    if (editingGrade.type === GradeType.REGULAR) {
        return subject.regularGrades.find(g => g.id === editingGrade.id) || null;
    }
    if (editingGrade.type === GradeType.MIDTERM) return subject.midtermGrade;
    if (editingGrade.type === GradeType.FINAL) return subject.finalGrade;
    return null;
  };

  // Determine TBM Color
  const tbmColorClass = tbmValue > 0 ? getColor(tbmValue).replace('bg-', 'text-').split(' ')[1] : 'text-gray-400';

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5 mb-4 hover:shadow-md transition duration-200">
      <div className="flex flex-col md:flex-row gap-6">

        {/* Subject Info & Stats */}
        <div className="w-full md:w-1/4 flex flex-col justify-between border-b md:border-b-0 md:border-r border-gray-100 pb-4 md:pb-0 md:pr-4">
          <div>
            <div className="flex justify-between items-start">
              <h3 className="font-bold text-lg text-gray-800">{subject.name}</h3>
              <button 
                onClick={() => { if(window.confirm(`Xóa môn ${subject.name}?`)) deleteSubject(subject.id); }}
                className="text-gray-400 hover:text-red-500 transition"
              >
                <span className="sr-only">Xóa môn</span>
                <XIcon size={16} />
              </button>
            </div>
            <div className="mt-3 flex items-center gap-2 text-sm text-gray-600 bg-gray-50 p-2 rounded-lg cursor-pointer hover:bg-indigo-50 transition" onClick={() => setBonusModalOpen(true)}>
                <Database size={14} className="text-indigo-500" />
                <span>Kho điểm cộng: <span className="font-bold text-indigo-600">{totalBonus.toFixed(1)}</span></span>
                <Plus size={14} className="ml-auto text-gray-400" />
            </div>
          </div>

          <div className="mt-4">
             <div className="text-xs text-gray-500 uppercase font-semibold tracking-wider mb-1">Trung Bình Môn</div>
             <div className={`text-3xl font-bold ${tbmColorClass}`}>
                {displayTbm}
             </div>
          </div>
        </div>

        {/* Grades Area */}
        <div className="flex-1 grid grid-cols-1 md:grid-cols-12 gap-4">

            {/* Regular Grades */}
            <div className="md:col-span-6 space-y-2">
                <div className="text-xs font-semibold text-gray-400 uppercase">Thường Xuyên (Hệ số 1)</div>
                <div className="flex flex-wrap gap-2">
                    {subject.regularGrades.map(g => (
                        <GradeChip 
                            key={g.id} 
                            grade={g} 
                            colorClass={getColor(g.value)} 
                            onClick={() => handleOpenEdit(g, GradeType.REGULAR)} 
                        />
                    ))}
                    <EmptySlot onClick={() => handleOpenAdd(GradeType.REGULAR)} />
                </div>
            </div>

            {/* Midterm */}
            <div className="md:col-span-3 space-y-2">
                <div className="text-xs font-semibold text-gray-400 uppercase">Giữa Kì (Hệ số 2)</div>
                <div>
                    {subject.midtermGrade ? (
                        <GradeChip 
                            grade={subject.midtermGrade} 
                            colorClass={getColor(subject.midtermGrade.value)} 
                            onClick={() => handleOpenEdit(subject.midtermGrade!, GradeType.MIDTERM)} 
                        />
                    ) : (
                        <EmptySlot onClick={() => handleOpenAdd(GradeType.MIDTERM)} label="Nhập giữa kì" />
                    )}
                </div>
            </div>

            {/* Final */}
            <div className="md:col-span-3 space-y-2">
                <div className="text-xs font-semibold text-gray-400 uppercase">Cuối Kì (Hệ số 3)</div>
                 <div>
                    {subject.finalGrade ? (
                        <GradeChip 
                            grade={subject.finalGrade} 
                            colorClass={getColor(subject.finalGrade.value)} 
                            onClick={() => handleOpenEdit(subject.finalGrade!, GradeType.FINAL)} 
                        />
                    ) : (
                        <EmptySlot onClick={() => handleOpenAdd(GradeType.FINAL)} label="Nhập cuối kì" />
                    )}
                </div>
            </div>

        </div>
      </div>

      <GradeInputModal 
        isOpen={modalOpen}
        onClose={() => setModalOpen(false)}
        gradeType={targetType}
        subjectName={subject.name}
        initialData={getInitialData()}
        maxBonusAvailable={totalBonus}
        onSave={(val, reason) => {
            if (editingGrade) {
                updateGrade(subject.id, editingGrade.id, targetType, val, reason);
            } else {
                addGrade(subject.id, targetType, val, reason);
            }
        }}
        onDelete={() => {
            if (editingGrade) {
                deleteGrade(subject.id, editingGrade.id, targetType);
            }
        }}
        onUseBonus={(amount) => {
            if (editingGrade) {
                useBonusPoint(subject.id, editingGrade.id, targetType, amount);
            }
        }}
      />

      <BonusModal
        isOpen={bonusModalOpen}
        onClose={() => setBonusModalOpen(false)}
        subjectName={subject.name}
        bonusPoints={subject.bonusPoints}
        onSave={(val, reason) => addBonusPoint(subject.id, val, reason)}
      />
    </div>
  );
};

// Helper icon component
const XIcon = ({ size }: { size: number }) => (
    <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
);

export default SubjectRow;

import React from 'react';
import { useGrade } from '../context/GradeContext';
import { TrendingUp, Award, AlertCircle } from 'lucide-react';

const StatsBoard: React.FC = () => {
  const { subjects } = useGrade();

  if (subjects.length === 0) return null;

  let totalTbm = 0;
  let count = 0;
  let missingGrades = 0;

  subjects.forEach(sub => {
    const regSum = sub.regularGrades.reduce((s, g) => s + g.value, 0);
    const midVal = sub.midtermGrade ? sub.midtermGrade.value : 0;
    const finalVal = sub.finalGrade ? sub.finalGrade.value : 0;
    const countReg = sub.regularGrades.length;

    let numerator = 0;
    let denominator = 0;

    if (countReg > 0 || sub.midtermGrade || sub.finalGrade) {
        numerator += regSum;
        denominator += countReg;

        if (sub.midtermGrade) {
            numerator += midVal * 2;
            denominator += 2;
        }
        if (sub.finalGrade) {
            numerator += finalVal * 3;
            denominator += 3;
        }

        if (denominator > 0) {
            totalTbm += (numerator / denominator);
            count++;
        }
    }

    if (!sub.midtermGrade || !sub.finalGrade) missingGrades++;
  });

  const overallAvg = count > 0 ? totalTbm / count : 0;

  // Classification
  let rank = 'Chưa xếp loại';
  let color = 'text-gray-500';

  if (overallAvg > 0) {
      if (overallAvg >= 8.0) { rank = 'Giỏi'; color = 'text-emerald-600'; }
      else if (overallAvg >= 6.5) { rank = 'Khá'; color = 'text-blue-600'; }
      else if (overallAvg >= 5.0) { rank = 'Trung Bình'; color = 'text-amber-600'; }
      else { rank = 'Yếu'; color = 'text-red-600'; }
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
      <div className="bg-white p-5 rounded-xl border border-gray-200 shadow-sm flex items-center gap-4">
        <div className="p-3 bg-indigo-50 text-indigo-600 rounded-full">
            <TrendingUp size={24} />
        </div>
        <div>
            <p className="text-sm text-gray-500 font-medium">Trung Bình Tất Cả Môn</p>
            <p className="text-2xl font-bold text-gray-800">{overallAvg.toFixed(2)}</p>
        </div>
      </div>

      <div className="bg-white p-5 rounded-xl border border-gray-200 shadow-sm flex items-center gap-4">
        <div className="p-3 bg-emerald-50 text-emerald-600 rounded-full">
            <Award size={24} />
        </div>
        <div>
            <p className="text-sm text-gray-500 font-medium">Xếp Loại Tạm Tính</p>
            <p className={`text-2xl font-bold ${color}`}>{rank}</p>
        </div>
      </div>

      <div className="bg-white p-5 rounded-xl border border-gray-200 shadow-sm flex items-center gap-4">
        <div className="p-3 bg-amber-50 text-amber-600 rounded-full">
            <AlertCircle size={24} />
        </div>
        <div>
            <p className="text-sm text-gray-500 font-medium">Cần Bổ Sung</p>
            <p className="text-2xl font-bold text-gray-800">
                {missingGrades} <span className="text-sm font-normal text-gray-500">môn thiếu điểm</span>
            </p>
        </div>
      </div>
    </div>
  );
};

export default StatsBoard;

import React, { useState } from 'react';
import { BookOpen, Download, Settings, Cloud, RefreshCw, CheckCircle, AlertCircle } from 'lucide-react';
import { useGrade } from '../context/GradeContext';
import { exportToCSV, loadData } from '../services/storageService';
import SettingsModal from './SettingsModal';

const Header: React.FC = () => {
  const { sheetUrl, setSheetUrl, syncStatus, forceSync, forceLoad } = useGrade();
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  const handleExport = () => {
    const data = loadData();
    exportToCSV(data);
  };

  const getSyncIcon = () => {
    switch (syncStatus) {
        case 'syncing': return <RefreshCw size={18} className="animate-spin" />;
        case 'saved': return <CheckCircle size={18} className="text-emerald-200" />;
        case 'error': return <AlertCircle size={18} className="text-red-300" />;
        default: return <Cloud size={18} />;
    }
  };

  const getSyncText = () => {
    switch (syncStatus) {
        case 'syncing': return 'Đang lưu...';
        case 'saved': return 'Đã lưu';
        case 'error': return 'Lỗi lưu';
        default: return 'Lưu Cloud';
    }
  };

  return (
    <header className="bg-indigo-600 text-white shadow-lg sticky top-0 z-40">
      <div className="container mx-auto px-4 py-4 flex justify-between items-center">
        <div className="flex items-center gap-3">
            <div className="bg-white/20 p-2 rounded-lg">
                <BookOpen size={24} />
            </div>
            <div>
                <h1 className="text-xl font-bold tracking-tight">GradeMaster</h1>
                <p className="text-indigo-200 text-xs hidden sm:block">Quản lý điểm số học sinh</p>
            </div>
        </div>

        <div className="flex items-center gap-2">
            {/* Sync Controls */}
            {sheetUrl && (
                 <div className="flex items-center gap-1 bg-indigo-800/50 rounded-lg p-1 mr-2 border border-indigo-500/30">
                     <button
                        onClick={forceLoad}
                        className="p-2 hover:bg-indigo-700 rounded-md transition text-indigo-200 hover:text-white"
                        title="Tải lại từ Google Sheet"
                     >
                        <Download size={16} />
                     </button>
                     <div className="w-px h-4 bg-indigo-500/50 mx-1"></div>
                     <button 
                        onClick={forceSync}
                        className="flex items-center gap-2 px-3 py-1.5 hover:bg-indigo-700 rounded-md transition text-xs font-medium"
                        title="Lưu ngay lập tức"
                     >
                        {getSyncIcon()}
                        <span className="hidden sm:inline">{getSyncText()}</span>
                     </button>
                 </div>
            )}

            <button 
                onClick={handleExport}
                className="hidden md:flex items-center gap-2 bg-indigo-700 hover:bg-indigo-800 px-4 py-2 rounded-lg text-sm font-medium transition"
                title="Xuất bảng điểm ra CSV"
            >
                <Download size={18} />
                <span className="hidden lg:inline">Xuất CSV</span>
            </button>

            <button
                onClick={() => setIsSettingsOpen(true)}
                className={`p-2 rounded-lg transition ${sheetUrl ? 'bg-indigo-700 text-white' : 'bg-white text-indigo-600 hover:bg-indigo-50'}`}
                title="Cài đặt kết nối"
            >
                <Settings size={20} />
            </button>
        </div>
      </div>

      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)}
        currentUrl={sheetUrl}
        onSaveUrl={setSheetUrl}
      />
    </header>
  );
};

export default Header;

import React, { useState } from 'react';
import { GradeProvider, useGrade } from './context/GradeContext';
import Header from './components/Header';
import SubjectRow from './components/SubjectRow';
import StatsBoard from './components/StatsBoard';
import { Plus } from 'lucide-react';

const Dashboard: React.FC = () => {
  const { subjects, addSubject } = useGrade();
  const [newSubjectName, setNewSubjectName] = useState('');
  const [isAdding, setIsAdding] = useState(false);

  const handleAddSubject = (e: React.FormEvent) => {
    e.preventDefault();
    if (newSubjectName.trim()) {
      addSubject(newSubjectName.trim());
      setNewSubjectName('');
      setIsAdding(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col pb-20">
      <Header />

      <main className="container mx-auto px-4 flex-grow max-w-5xl pt-8">

        <StatsBoard />

        <div className="flex justify-between items-end mb-4">
            <h2 className="text-gray-700 font-bold text-lg">Danh sách môn học ({subjects.length})</h2>
            {!isAdding ? (
                <button 
                    onClick={() => setIsAdding(true)}
                    className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition shadow-sm hover:shadow"
                >
                    <Plus size={18} />
                    Thêm môn học
                </button>
            ) : (
                <form onSubmit={handleAddSubject} className="flex gap-2 animate-fade-in-right">
                    <input 
                        type="text" 
                        placeholder="Tên môn học..." 
                        value={newSubjectName}
                        onChange={(e) => setNewSubjectName(e.target.value)}
                        className="border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                        autoFocus
                    />
                    <button 
                        type="submit"
                        className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700"
                    >
                        Lưu
                    </button>
                    <button 
                        type="button"
                        onClick={() => setIsAdding(false)}
                        className="bg-gray-200 text-gray-700 px-4 py-2 rounded-lg hover:bg-gray-300"
                    >
                        Hủy
                    </button>
                </form>
            )}
        </div>

        {subjects.length === 0 ? (
            <div className="text-center py-20 bg-white rounded-xl border border-dashed border-gray-300">
                <div className="text-gray-400 mb-4">Chưa có môn học nào được thêm.</div>
                <button 
                    onClick={() => setIsAdding(true)}
                    className="text-indigo-600 font-medium hover:underline"
                >
                    Thêm môn học đầu tiên
                </button>
            </div>
        ) : (
            <div className="space-y-4">
                {subjects.map(sub => (
                    <SubjectRow key={sub.id} subject={sub} />
                ))}
            </div>
        )}
      </main>

      <footer className="mt-12 text-center text-gray-400 text-sm py-6">
        <p>&copy; 2026 Grade Master. Tự động lưu dữ liệu vào trình duyệt.</p>
        <p className="text-xs mt-1">Công thức: Tự động điều chỉnh theo hệ số TX:1, GK:2, CK:3</p>
      </footer>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <GradeProvider>
      <Dashboard />
    </GradeProvider>
  );
};

export default App;

