### Hướng dẫn Kết Nối Google Sheet

Vì bạn yêu cầu trả lời bằng văn bản, đây là cách cài đặt:

1.  **Tạo Google Sheet mới**: Truy cập [sheets.new](https://sheets.new) để tạo một bảng tính. Đặt tên là "GradeMaster DB".
2.  **Mở Script Editor**: Tại Google Sheet, chọn menu **Tiện ích mở rộng (Extensions)** > **Apps Script**.
3.  **Dán mã nguồn**: Xóa hết nội dung trong file `Code.gs` và copy đoạn mã dưới đây vào:
    ```javascript
    function doGet(e) { return handleRequest(e); }
    function doPost(e) { return handleRequest(e); }

    function handleRequest(e) {
      var lock = LockService.getScriptLock();
      lock.tryLock(10000);
      try {
        var doc = SpreadsheetApp.getActiveSpreadsheet();
        var dbSheet = doc.getSheetByName("DB_RAW");
        if (!dbSheet) { dbSheet = doc.insertSheet("DB_RAW"); dbSheet.hideSheet(); }

        var action = e.parameter.action;
        if (e.postData && e.postData.contents) {
          var body = JSON.parse(e.postData.contents);
          action = body.action;
          var data = body.data;
        }

        if (action === "save") {
          dbSheet.getRange(1, 1).setValue(JSON.stringify(data));
          exportToReadableSheet(doc, data);
          return response({ success: true, message: "Saved" });
        } else {
          var json = dbSheet.getRange(1, 1).getValue();
          var data = json ? JSON.parse(json) : { subjects: [] };
          return response({ success: true, data: data });
        }
      } catch (err) { return response({ success: false, message: err.toString() }); }
      finally { lock.releaseLock(); }
    }

    function response(data) {
      return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON);
    }

    function exportToReadableSheet(doc, data) {
      // Vì chỉ còn 1 kì, ta lưu vào sheet tên "BangDiem"
      var sheet = doc.getSheetByName("BangDiem");
      if (!sheet) sheet = doc.insertSheet("BangDiem");
      sheet.clear();
      sheet.appendRow(["Môn Học", "Điểm TX", "Giữa Kì", "Cuối Kì", "Điểm Cộng Dư", "Trung Bình"]);
      sheet.getRange(1, 1, 1, 6).setFontWeight("bold").setBackground("#e0e0e0");

      if (!data.subjects) return;
      var rows = data.subjects.map(function(sub) {
        var reg = sub.regularGrades.map(g => g.value).join(", ");
        var mid = sub.midtermGrade ? sub.midtermGrade.value : "";
        var final = sub.finalGrade ? sub.finalGrade.value : "";
        var bonus = sub.bonusPoints.reduce((s, b) => s + b.value, 0);

        // Tính TBM y hệt logic JS
        var regSum = sub.regularGrades.reduce((s, g) => s + g.value, 0);
        var count = sub.regularGrades.length;
        var num = regSum;
        var den = count;
        if(mid) { num += mid*2; den += 2; }
        if(final) { num += final*3; den += 3; }
        var tbm = den > 0 ? (num/den).toFixed(2) : "";

        return [sub.name, reg, mid, final, bonus, tbm];
      });
      if(rows.length) sheet.getRange(2, 1, rows.length, 6).setValues(rows);
    }
    ```
4.  **Triển khai (Deploy)**:
    *   Bấm nút **Deploy (Triển khai)** màu xanh > **New deployment (Tùy chọn triển khai mới)**.
    *   Chọn loại **Web app**.
    *   Phần "Who has access" (Ai có quyền truy cập): **BẮT BUỘC chọn "Anyone" (Bất kỳ ai)**.
    *   Bấm **Deploy**.
5.  **Kết nối**: Copy URL vừa tạo, quay lại web GradeMaster > Bấm nút Cài đặt (Bánh răng) > Dán URL vào > Lưu.

