export enum GradeType {
  REGULAR = 'REGULAR', // Hệ số 1 (Thường xuyên)
  MIDTERM = 'MIDTERM', // Hệ số 2 (Giữa kì)
  FINAL = 'FINAL',     // Hệ số 3 (Cuối kì)
}

export interface Grade {
  id: string;
  value: number;
  reason: string; // Lí do có điểm
  timestamp: number;
}

export interface BonusPoint {
  id: string;
  value: number;
  reason: string;
  timestamp: number;
}

export interface SubjectData {
  id: string;
  name: string;
  regularGrades: Grade[];
  midtermGrade: Grade | null;
  finalGrade: Grade | null;
  bonusPoints: BonusPoint[]; // Kho điểm cộng
}

// Schedule Types
export interface PeriodInfo {
  subjectName: string;
  teacherName: string;
}

export interface DaySchedule {
  date: string; // DD/MM/YYYY
  morning: PeriodInfo[]; // 5 periods (0-4)
  afternoon: PeriodInfo[]; // 5 periods (0-4)
}

export interface WeekSchedule {
  id: string;
  name: string; // e.g., "Tuần 1"
  days: {
    mon: DaySchedule;
    tue: DaySchedule;
    wed: DaySchedule;
    thu: DaySchedule;
    fri: DaySchedule;
    sat: DaySchedule;
    sun: DaySchedule;
  };
}

export interface AppState {
  subjects: SubjectData[];
  weeks: WeekSchedule[];
}

import { AppState } from '../types';
import { STORAGE_KEY } from '../constants';

const CONFIG_KEY = 'grademaster_config_v1';

export const loadData = (): AppState => {
  try {
    const serialized = localStorage.getItem(STORAGE_KEY);
    if (serialized) {
      const parsed = JSON.parse(serialized);
      // Migration: If old structure exists (subjectsSem1/2), migrate to simple subjects list (taking Sem 2 as requested)
      if (parsed.subjectsSem2) {
          return { subjects: parsed.subjectsSem2, weeks: [] };
      }
      // Ensure weeks exists
      if (!parsed.weeks) {
          return { ...parsed, weeks: [] };
      }
      return parsed;
    }
  } catch (e) {
    console.error("Failed to load data", e);
  }
  return {
    subjects: [],
    weeks: []
  };
};

export const saveData = (data: AppState) => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
  } catch (e) {
    console.error("Failed to save data", e);
  }
};

export const saveConfig = (url: string) => {
    localStorage.setItem(CONFIG_KEY, JSON.stringify({ sheetUrl: url }));
};

export const loadConfig = (): { sheetUrl: string } => {
    try {
        const conf = localStorage.getItem(CONFIG_KEY);
        if (conf) return JSON.parse(conf);
    } catch (e) {}
    return { sheetUrl: '' };
};

export const exportToCSV = (data: AppState) => {
  const subjects = data.subjects;

  // Header
  let csvContent = "data:text/csv;charset=utf-8,";
  csvContent += "Môn Học,Điểm Thường Xuyên,Điểm Giữa Kì,Điểm Cuối Kì,Điểm Cộng Còn Lại,Trung Bình Môn\n";

  subjects.forEach(sub => {
    const regular = sub.regularGrades.map(g => `${g.value} (${g.reason})`).join("; ");
    const midterm = sub.midtermGrade ? `${sub.midtermGrade.value} (${sub.midtermGrade.reason})` : "";
    const final = sub.finalGrade ? `${sub.finalGrade.value} (${sub.finalGrade.reason})` : "";

    // Calculate TBM Logic for Export matches the new requirement
    const regSum = sub.regularGrades.reduce((sum, g) => sum + g.value, 0);
    const countReg = sub.regularGrades.length;
    const midVal = sub.midtermGrade ? sub.midtermGrade.value : 0;
    const finalVal = sub.finalGrade ? sub.finalGrade.value : 0;

    let tbm = "N/A";
    let numerator = 0;
    let denominator = 0;

    if (countReg > 0 || sub.midtermGrade || sub.finalGrade) {
        numerator += regSum;
        denominator += countReg;

        if (sub.midtermGrade) {
            numerator += midVal * 2;
            denominator += 2;
        }
        if (sub.finalGrade) {
            numerator += finalVal * 3;
            denominator += 3;
        }

        if (denominator > 0) {
            tbm = (numerator / denominator).toFixed(2);
        }
    }

    const bonusTotal = sub.bonusPoints.reduce((sum, b) => sum + b.value, 0);

    const row = [
      `"${sub.name}"`,
      `"${regular}"`,
      `"${midterm}"`,
      `"${final}"`,
      `"${bonusTotal}"`,
      `"${tbm}"`
    ].join(",");
    csvContent += row + "\r\n";
  });

  const encodedUri = encodeURI(csvContent);
  const link = document.createElement("a");
  link.setAttribute("href", encodedUri);
  link.setAttribute("download", `bang_diem_ki_2.csv`);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import { AppState, SubjectData, Grade, GradeType, BonusPoint, WeekSchedule } from '../types';
import { loadData, saveData, saveConfig, loadConfig } from '../services/storageService';
import { syncToSheet, loadFromSheet } from '../services/googleSheetService';
import { v4 as uuidv4 } from 'uuid';

interface GradeContextType {
  subjects: SubjectData[];
  weeks: WeekSchedule[];
  addSubject: (name: string) => void;
  deleteSubject: (id: string) => void;
  addGrade: (subjectId: string, type: GradeType, value: number, reason: string) => void;
  updateGrade: (subjectId: string, gradeId: string, type: GradeType, newValue: number, newReason: string) => void;
  deleteGrade: (subjectId: string, gradeId: string, type: GradeType) => void;
  addBonusPoint: (subjectId: string, value: number, reason: string) => void;
  useBonusPoint: (subjectId: string, gradeId: string, gradeType: GradeType, bonusAmount: number) => boolean;

  // Schedule
  addWeek: (week: WeekSchedule) => void;
  updateWeek: (week: WeekSchedule) => void;
  deleteWeek: (id: string) => void;

  // Cloud Sync
  sheetUrl: string;
  setSheetUrl: (url: string) => void;
  syncStatus: 'idle' | 'syncing' | 'saved' | 'error';
  lastSyncTime: Date | null;
  forceSync: () => Promise<void>;
  forceLoad: () => Promise<void>;
}

const GradeContext = createContext<GradeContextType | undefined>(undefined);

export const GradeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [data, setData] = useState<AppState>({ subjects: [], weeks: [] });
  const [sheetUrl, setSheetUrlState] = useState<string>('');
  const [syncStatus, setSyncStatus] = useState<'idle' | 'syncing' | 'saved' | 'error'>('idle');
  const [lastSyncTime, setLastSyncTime] = useState<Date | null>(null);

  const debounceTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    const loaded = loadData();
    setData(loaded);
    const config = loadConfig();
    if (config.sheetUrl) {
        setSheetUrlState(config.sheetUrl);
    }
  }, []);

  const setSheetUrl = (url: string) => {
      setSheetUrlState(url);
      saveConfig(url);
  };

  const handleSyncToCloud = useCallback(async (currentData: AppState, url: string) => {
    if (!url) return;
    setSyncStatus('syncing');
    const result = await syncToSheet(url, currentData);
    if (result.success) {
        setSyncStatus('saved');
        setLastSyncTime(new Date());
        setTimeout(() => setSyncStatus('idle'), 3000);
    } else {
        setSyncStatus('error');
    }
  }, []);

  useEffect(() => {
    saveData(data);

    if (sheetUrl) {
        if (debounceTimerRef.current) clearTimeout(debounceTimerRef.current);
        setSyncStatus('idle'); 

        debounceTimerRef.current = setTimeout(() => {
            handleSyncToCloud(data, sheetUrl);
        }, 3000); 
    }

    return () => {
        if (debounceTimerRef.current) clearTimeout(debounceTimerRef.current);
    };
  }, [data, sheetUrl, handleSyncToCloud]);

  const forceSync = async () => {
      if (!sheetUrl) return;
      await handleSyncToCloud(data, sheetUrl);
  };

  const forceLoad = async () => {
      if (!sheetUrl) return;
      setSyncStatus('syncing');
      const result = await loadFromSheet(sheetUrl);
      if (result.success && result.data) {
          const loadedData = result.data as any;
          // Compatibility handling
          const newState: AppState = {
              subjects: loadedData.subjectsSem2 || loadedData.subjects || [],
              weeks: loadedData.weeks || []
          };
          setData(newState);
          setSyncStatus('saved');
          setLastSyncTime(new Date());
          saveData(newState);
          setTimeout(() => setSyncStatus('idle'), 3000);
      } else {
          setSyncStatus('error');
          alert(result.message || "Lỗi tải dữ liệu");
      }
  };

  const currentSubjects = data.subjects;
  const currentWeeks = data.weeks || [];

  const updateSubjects = useCallback((newSubjects: SubjectData[]) => {
    setData(prev => ({ ...prev, subjects: newSubjects }));
  }, []);

  const updateWeeks = useCallback((newWeeks: WeekSchedule[]) => {
    setData(prev => ({ ...prev, weeks: newWeeks }));
  }, []);

  const addSubject = (name: string) => {
    const newSubject: SubjectData = {
      id: uuidv4(),
      name,
      regularGrades: [],
      midtermGrade: null,
      finalGrade: null,
      bonusPoints: []
    };
    updateSubjects([...currentSubjects, newSubject]);
  };

  const deleteSubject = (id: string) => {
    updateSubjects(currentSubjects.filter(s => s.id !== id));
  };

  const addGrade = (subjectId: string, type: GradeType, value: number, reason: string) => {
    const newGrade: Grade = {
      id: uuidv4(),
      value,
      reason,
      timestamp: Date.now()
    };

    const newSubjects = currentSubjects.map(sub => {
      if (sub.id !== subjectId) return sub;
      if (type === GradeType.REGULAR) {
        return { ...sub, regularGrades: [...sub.regularGrades, newGrade] };
      } else if (type === GradeType.MIDTERM) {
        return { ...sub, midtermGrade: newGrade };
      } else {
        return { ...sub, finalGrade: newGrade };
      }
    });
    updateSubjects(newSubjects);
  };

  const updateGrade = (subjectId: string, gradeId: string, type: GradeType, newValue: number, newReason: string) => {
    const newSubjects = currentSubjects.map(sub => {
      if (sub.id !== subjectId) return sub;

      if (type === GradeType.REGULAR) {
        return {
          ...sub,
          regularGrades: sub.regularGrades.map(g => g.id === gradeId ? { ...g, value: newValue, reason: newReason } : g)
        };
      } else if (type === GradeType.MIDTERM && sub.midtermGrade?.id === gradeId) {
        return { ...sub, midtermGrade: { ...sub.midtermGrade, value: newValue, reason: newReason } };
      } else if (type === GradeType.FINAL && sub.finalGrade?.id === gradeId) {
        return { ...sub, finalGrade: { ...sub.finalGrade, value: newValue, reason: newReason } };
      }
      return sub;
    });
    updateSubjects(newSubjects);
  };

  const deleteGrade = (subjectId: string, gradeId: string, type: GradeType) => {
     const newSubjects = currentSubjects.map(sub => {
      if (sub.id !== subjectId) return sub;

      if (type === GradeType.REGULAR) {
        return { ...sub, regularGrades: sub.regularGrades.filter(g => g.id !== gradeId) };
      } else if (type === GradeType.MIDTERM && sub.midtermGrade?.id === gradeId) {
        return { ...sub, midtermGrade: null };
      } else if (type === GradeType.FINAL && sub.finalGrade?.id === gradeId) {
        return { ...sub, finalGrade: null };
      }
      return sub;
    });
    updateSubjects(newSubjects);
  };

  const addBonusPoint = (subjectId: string, value: number, reason: string) => {
    const newBonus: BonusPoint = { id: uuidv4(), value, reason, timestamp: Date.now() };
    const newSubjects = currentSubjects.map(sub => {
      if (sub.id !== subjectId) return sub;
      return { ...sub, bonusPoints: [...sub.bonusPoints, newBonus] };
    });
    updateSubjects(newSubjects);
  };

  const useBonusPoint = (subjectId: string, gradeId: string, gradeType: GradeType, bonusAmount: number): boolean => {
    const subject = currentSubjects.find(s => s.id === subjectId);
    if (!subject) return false;

    const totalBonus = subject.bonusPoints.reduce((sum, b) => sum + b.value, 0);
    if (totalBonus < bonusAmount) return false;

    let remainingToConsume = bonusAmount;
    let newBonusPoints = [...subject.bonusPoints];

    newBonusPoints = newBonusPoints.map(bp => {
        if (remainingToConsume <= 0) return bp;

        if (bp.value <= remainingToConsume) {
            remainingToConsume -= bp.value;
            return { ...bp, value: 0 }; 
        } else {
            const newVal = bp.value - remainingToConsume;
            remainingToConsume = 0;
            return { ...bp, value: newVal };
        }
    }).filter(bp => bp.value > 0);

    let updatedRegular = subject.regularGrades;
    let updatedMid = subject.midtermGrade;
    let updatedFinal = subject.finalGrade;

    const appendReason = ` (+${bonusAmount})`;

    if (gradeType === GradeType.REGULAR) {
        updatedRegular = updatedRegular.map(g => g.id === gradeId ? { ...g, value: g.value + bonusAmount, reason: g.reason + appendReason } : g);
    } else if (gradeType === GradeType.MIDTERM && updatedMid?.id === gradeId) {
        updatedMid = { ...updatedMid, value: updatedMid.value + bonusAmount, reason: updatedMid.reason + appendReason };
    } else if (gradeType === GradeType.FINAL && updatedFinal?.id === gradeId) {
        updatedFinal = { ...updatedFinal, value: updatedFinal.value + bonusAmount, reason: updatedFinal.reason + appendReason };
    }

    const newSubjects = currentSubjects.map(sub => {
        if (sub.id !== subjectId) return sub;
        return {
            ...sub,
            bonusPoints: newBonusPoints,
            regularGrades: updatedRegular,
            midtermGrade: updatedMid,
            finalGrade: updatedFinal
        };
    });
    updateSubjects(newSubjects);
    return true;
  };

  const addWeek = (week: WeekSchedule) => {
    updateWeeks([...currentWeeks, week]);
  };

  const updateWeek = (week: WeekSchedule) => {
    updateWeeks(currentWeeks.map(w => w.id === week.id ? week : w));
  };

  const deleteWeek = (id: string) => {
    updateWeeks(currentWeeks.filter(w => w.id !== id));
  };

  return (
    <GradeContext.Provider value={{ 
      subjects: currentSubjects, 
      weeks: currentWeeks,
      addSubject, 
      deleteSubject,
      addGrade,
      updateGrade,
      deleteGrade,
      addBonusPoint,
      useBonusPoint,
      addWeek,
      updateWeek,
      deleteWeek,
      sheetUrl,
      setSheetUrl,
      syncStatus,
      lastSyncTime,
      forceSync,
      forceLoad
    }}>
      {children}
    </GradeContext.Provider>
  );
};

export const useGrade = () => {
  const context = useContext(GradeContext);
  if (!context) throw new Error("useGrade must be used within a GradeProvider");
  return context;
};

import React from 'react';
import { useGrade } from '../context/GradeContext';
import { TrendingUp, Award } from 'lucide-react';

const StatsBoard: React.FC = () => {
  const { subjects } = useGrade();

  if (subjects.length === 0) return null;

  let totalTbm = 0;
  let count = 0;
  const tbmList: number[] = [];

  subjects.forEach(sub => {
    const regSum = sub.regularGrades.reduce((s, g) => s + g.value, 0);
    const midVal = sub.midtermGrade ? sub.midtermGrade.value : 0;
    const finalVal = sub.finalGrade ? sub.finalGrade.value : 0;
    const countReg = sub.regularGrades.length;

    let numerator = 0;
    let denominator = 0;

    if (countReg > 0 || sub.midtermGrade || sub.finalGrade) {
        numerator += regSum;
        denominator += countReg;

        if (sub.midtermGrade) {
            numerator += midVal * 2;
            denominator += 2;
        }
        if (sub.finalGrade) {
            numerator += finalVal * 3;
            denominator += 3;
        }

        if (denominator > 0) {
            const tbm = numerator / denominator;
            totalTbm += tbm;
            tbmList.push(tbm);
            count++;
        }
    }
  });

  const overallAvg = count > 0 ? totalTbm / count : 0;

  // Classification Logic (Simplified Circular 22)
  // Xuất sắc: 6 môn >= 9.0, còn lại >= 6.5
  // Giỏi: 6 môn >= 8.0, còn lại >= 6.5
  // Khá: 6 môn >= 6.5, còn lại >= 5.0

  let rank = 'Chưa xếp loại';
  let color = 'text-gray-500';
  let bgColor = 'bg-gray-50';

  if (tbmList.length > 0) {
      // Sort descending for easier counting
      const sortedTbm = [...tbmList].sort((a, b) => b - a);
      const minTbm = sortedTbm[sortedTbm.length - 1]; // Lowest score

      const count90 = sortedTbm.filter(s => s >= 9.0).length;
      const count80 = sortedTbm.filter(s => s >= 8.0).length;
      const count65 = sortedTbm.filter(s => s >= 6.5).length;

      // Logic check
      // For classification, we usually need enough subjects. 
      // Assuming if they have less than 6 subjects entered, we rely on "all subjects must meet criteria".
      const thresholdCount = Math.min(6, tbmList.length);

      if (count90 >= thresholdCount && minTbm >= 6.5) {
          rank = 'Xuất sắc';
          color = 'text-purple-600';
          bgColor = 'bg-purple-50';
      } else if (count80 >= thresholdCount && minTbm >= 6.5) {
          rank = 'Giỏi';
          color = 'text-emerald-600';
          bgColor = 'bg-emerald-50';
      } else if (count65 >= thresholdCount && minTbm >= 5.0) {
          rank = 'Khá';
          color = 'text-blue-600';
          bgColor = 'bg-blue-50';
      } else if (minTbm >= 3.5) {
          // Fallback logic for Trung Binh/Yeu based on general knowledge since not specified fully
           rank = 'Trung Bình';
           color = 'text-amber-600';
           bgColor = 'bg-amber-50';
      } else {
           rank = 'Yếu';
           color = 'text-red-600';
           bgColor = 'bg-red-50';
      }
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
      <div className="bg-white p-5 rounded-xl border border-gray-200 shadow-sm flex items-center gap-4">
        <div className="p-3 bg-indigo-50 text-indigo-600 rounded-full">
            <TrendingUp size={24} />
        </div>
        <div>
            <p className="text-sm text-gray-500 font-medium">Trung Bình Tất Cả Môn</p>
            <p className="text-2xl font-bold text-gray-800">{overallAvg.toFixed(2)}</p>
        </div>
      </div>

      <div className="bg-white p-5 rounded-xl border border-gray-200 shadow-sm flex items-center gap-4">
        <div className={`p-3 ${bgColor} ${color} rounded-full`}>
            <Award size={24} />
        </div>
        <div>
            <p className="text-sm text-gray-500 font-medium">Xếp Loại</p>
            <p className={`text-2xl font-bold ${color}`}>{rank}</p>
        </div>
      </div>
    </div>
  );
};

