import React, { useState, useEffect } from 'react';
import { X, Save, Plus, Trash2 } from 'lucide-react';
import { WeekSchedule, DaySchedule, PeriodInfo } from '../types';
import { v4 as uuidv4 } from 'uuid';
import { useGrade } from '../context/GradeContext';

interface ScheduleModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const DAYS = [
    { key: 'mon', label: 'Thứ 2' },
    { key: 'tue', label: 'Thứ 3' },
    { key: 'wed', label: 'Thứ 4' },
    { key: 'thu', label: 'Thứ 5' },
    { key: 'fri', label: 'Thứ 6' },
    { key: 'sat', label: 'Thứ 7' },
    { key: 'sun', label: 'CN' },
];

const PERIODS = [0, 1, 2, 3, 4];

const ScheduleModal: React.FC<ScheduleModalProps> = ({ isOpen, onClose }) => {
  const { weeks, addWeek, updateWeek, deleteWeek, subjects } = useGrade();
  const [selectedWeekId, setSelectedWeekId] = useState<string | 'new'>('new');
  const [formData, setFormData] = useState<WeekSchedule | null>(null);

  useEffect(() => {
    if (isOpen) {
        if (weeks.length > 0) {
            setSelectedWeekId(weeks[0].id);
            setFormData(weeks[0]);
        } else {
            initNewWeek();
        }
    }
  }, [isOpen]);

  const initNewWeek = () => {
    setSelectedWeekId('new');
    const emptyDay = (): DaySchedule => ({ 
        date: '', 
        morning: Array(5).fill({ subjectName: '', teacherName: '' }), 
        afternoon: Array(5).fill({ subjectName: '', teacherName: '' }) 
    });
    setFormData({
        id: uuidv4(),
        name: `Tuần ${weeks.length + 1}`,
        days: {
            mon: emptyDay(), tue: emptyDay(), wed: emptyDay(), thu: emptyDay(), fri: emptyDay(), sat: emptyDay(), sun: emptyDay()
        }
    });
  };

  const handleWeekSelect = (id: string) => {
    if (id === 'new') {
        initNewWeek();
    } else {
        const w = weeks.find(wk => wk.id === id);
        if (w) {
            setSelectedWeekId(id);
            setFormData(JSON.parse(JSON.stringify(w))); // Deep copy
        }
    }
  };

  const handleCellChange = (dayKey: string, session: 'morning' | 'afternoon', index: number, field: keyof PeriodInfo, value: string) => {
    if (!formData) return;
    const newDays = { ...formData.days } as any;
    const day = newDays[dayKey] as DaySchedule;

    // Create new array to avoid mutation issues
    const newPeriods = [...(session === 'morning' ? day.morning : day.afternoon)];
    newPeriods[index] = { ...newPeriods[index], [field]: value };

    if (session === 'morning') day.morning = newPeriods;
    else day.afternoon = newPeriods;

    setFormData({ ...formData, days: newDays });
  };

  const handleDateChange = (dayKey: string, date: string) => {
      if (!formData) return;
      const newDays = { ...formData.days } as any;
      newDays[dayKey].date = date;
      setFormData({ ...formData, days: newDays });
  };

  const handleSave = () => {
      if (!formData) return;
      if (selectedWeekId === 'new') {
          addWeek(formData);
          // Set to the newly created id
          setSelectedWeekId(formData.id);
      } else {
          updateWeek(formData);
      }
      alert('Đã lưu thời khóa biểu!');
  };

  const handleDelete = () => {
      if (selectedWeekId !== 'new' && window.confirm('Xóa tuần này?')) {
          deleteWeek(selectedWeekId);
          if (weeks.length > 1) { // weeks still has the deleted one currently
             const others = weeks.filter(w => w.id !== selectedWeekId);
             if (others.length > 0) handleWeekSelect(others[0].id);
             else initNewWeek();
          } else {
             initNewWeek();
          }
      }
  };

  if (!isOpen || !formData) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-xl shadow-xl w-full max-w-6xl h-[90vh] flex flex-col animate-fade-in-up">
        {/* Header */}
        <div className="bg-indigo-600 px-6 py-4 flex justify-between items-center flex-shrink-0 rounded-t-xl">
          <h3 className="text-white font-semibold text-lg">Quản lý Thời Khóa Biểu</h3>
          <button onClick={onClose} className="text-white hover:bg-indigo-700 p-1 rounded-full transition">
            <X size={20} />
          </button>
        </div>

        {/* Toolbar */}
        <div className="p-4 bg-gray-50 border-b border-gray-200 flex gap-4 items-center flex-shrink-0">
             <select 
                value={selectedWeekId} 
                onChange={(e) => handleWeekSelect(e.target.value)}
                className="border border-gray-300 rounded px-3 py-2 bg-white font-medium"
             >
                 {weeks.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
                 <option value="new">+ Thêm tuần mới</option>
             </select>

             <input 
                type="text" 
                value={formData.name}
                onChange={(e) => setFormData({...formData, name: e.target.value})}
                placeholder="Tên tuần..."
                className="border border-gray-300 rounded px-3 py-2"
             />

             <div className="flex-grow"></div>

             {selectedWeekId !== 'new' && (
                 <button onClick={handleDelete} className="text-red-500 hover:bg-red-50 p-2 rounded flex items-center gap-1">
                     <Trash2 size={18} /> Xóa
                 </button>
             )}
             <button onClick={handleSave} className="bg-indigo-600 text-white px-4 py-2 rounded flex items-center gap-2 hover:bg-indigo-700">
                 <Save size={18} /> Lưu TKB
             </button>
        </div>

        {/* Grid Content */}
        <div className="flex-1 overflow-auto p-4">
            <div className="min-w-[1000px]">
                <div className="grid grid-cols-8 gap-2 mb-2 sticky top-0 bg-white z-10 pb-2 border-b">
                    <div className="font-bold text-center p-2 bg-gray-100 rounded">Tiết</div>
                    {DAYS.map(d => (
                        <div key={d.key} className="text-center bg-indigo-50 rounded p-2 border border-indigo-100">
                            <div className="font-bold text-indigo-800">{d.label}</div>
                            <input 
                                type="text" 
                                placeholder="dd/mm" 
                                className="w-full text-xs text-center bg-transparent border-b border-indigo-200 outline-none"
                                value={(formData.days as any)[d.key].date}
                                onChange={(e) => handleDateChange(d.key, e.target.value)}
                            />
                        </div>
                    ))}
                </div>

                {/* Morning */}
                <div className="mb-4">
                    <div className="font-bold text-gray-500 mb-2 px-2 uppercase text-xs">Buổi Sáng</div>
                    {PERIODS.map(pIndex => (
                        <div key={`m-${pIndex}`} className="grid grid-cols-8 gap-2 mb-2">
