                    ))}
                </div>

                {/* Afternoon */}
                <div>
                    <div className="font-bold text-gray-500 mb-2 px-2 uppercase text-xs">Buổi Chiều</div>
                     {PERIODS.map(pIndex => (
                        <div key={`a-${pIndex}`} className="grid grid-cols-8 gap-2 mb-2">
                             <div className="flex items-center justify-center font-bold text-gray-400 bg-gray-50 rounded">
                                 {pIndex + 1}
                             </div>
                             {DAYS.map(d => {
                                 const period = (formData.days as any)[d.key].afternoon[pIndex];
                                 return (
                                     <div key={`a-${d.key}-${pIndex}`} className="bg-white border border-gray-200 rounded p-1 shadow-sm flex flex-col gap-1">
